+using System.ComponentModel;
+using System.Net;
+using Microsoft.Agents.AI;
+using Microsoft.Extensions.AI;
+using OpenAI;
+
+var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
+    ?? throw new InvalidOperationException(
+        "Set the OPENAI_API_KEY environment variable before running.");
+
+var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL")
+    ?? "gpt-4o-mini-2024-07-18";
+
+// --- Build the chat client through the MEAI abstraction ---
+IChatClient chatClient = new OpenAIClient(apiKey)
+    .GetChatClient(modelId)
+    .AsIChatClient();
+
+// --- Create the tools ---
+using var httpClient = new HttpClient();
+httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
+
+var researchTools = new ResearchTools(httpClient);
+var tools = new AITool[]
+{
+    AIFunctionFactory.Create(researchTools.SearchWebAsync),
+    AIFunctionFactory.Create(researchTools.SaveNote),
+    AIFunctionFactory.Create(researchTools.GetNotes),
+};
+
+// --- Create the agent ---
+var agent = new ChatClientAgent(
+    chatClient,
+    instructions: """
+        You are a research assistant. When given a topic:
+        1. Search the web for several different aspects of the topic.
+        2. Save the most important findings as notes using descriptive labels.
+        3. After gathering enough information, retrieve your notes and write a
+           comprehensive summary with key facts and sources.
+        Always perform at least two distinct searches before summarizing.
+        """,
+    name: "ResearchAgent",
+    description: "An agent that researches topics by searching the web and taking notes.",
+    tools: tools);
+
+// --- Interactive loop ---
+Console.WriteLine("Research Agent ready. Type a topic to research (or 'exit' to quit).\n");
+
+while (true)
+{
+    Console.Write("> ");
+    var topic = Console.ReadLine()?.Trim();
+
+    if (string.IsNullOrEmpty(topic))
+        continue;
+
+    if (topic.Equals("exit", StringComparison.OrdinalIgnoreCase))
+        break;
+
+    Console.WriteLine($"\nResearching: {topic}\n");
+
+    researchTools.ClearNotes();
+
+    var session = await agent.CreateSessionAsync(
+        conversationId: Guid.NewGuid().ToString());
+
+    var runOptions = new ChatClientAgentRunOptions(new ChatOptions
+    {
+        Temperature = 0f,
+        MaxOutputTokens = 2048,
+    });
+
+    try
+    {
+        await foreach (var update in agent.RunStreamingAsync(
+            $"Research the following topic thoroughly and provide a summary:\n\n{topic}",
+            session,
+            runOptions))
+        {
+            if (!string.IsNullOrEmpty(update.Text))
+                Console.Write(update.Text);
+        }
+    }
+    catch (Exception ex)
+    {
+        Console.WriteLine($"\nError during research: {ex.Message}");
+    }
+
+    Console.WriteLine("\n");
+}
+
+// =============================================================================
+// Tools
+// =============================================================================
+
+/// <summary>Tools available to the research agent.</summary>
+sealed class ResearchTools(HttpClient httpClient)
+{
+    private readonly List<string> _notes = [];
+
+    [Description("Search the web for information on a query. Returns search result snippets.")]
+    public async Task<string> SearchWebAsync(
+        [Description("The search query")] string query,
+        CancellationToken cancellationToken = default)
+    {
+        try
+        {
+            var encoded = Uri.EscapeDataString(query);
+            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
+            var html = await httpClient.GetStringAsync(url, cancellationToken);
+            var snippets = ExtractSnippets(html);
+
+            return snippets.Count > 0
+                ? string.Join("\n\n", snippets)
+                : "No results found.";
+        }
+        catch (Exception ex)
+        {
+            return $"Search failed: {ex.Message}";
+        }
+    }
+
+    [Description("Save a research note. Use this to record key findings during research.")]
+    public string SaveNote(
+        [Description("A short label or category for the note")] string label,
+        [Description("The note content to save")] string content)
+    {
+        _notes.Add($"[{label}] {content}");
+        return $"Note saved. Total notes: {_notes.Count}";
+    }
+
+    [Description("Retrieve all saved research notes.")]
+    public string GetNotes()
+    {
+        return _notes.Count == 0
+            ? "No notes saved yet."
+            : string.Join("\n", _notes.Select((n, i) => $"{i + 1}. {n}"));
+    }
+
+    public void ClearNotes() => _notes.Clear();
+
+    private static List<string> ExtractSnippets(string html)
+    {
+        var snippets = new List<string>();
+        const string marker = "result__snippet";
+        var idx = 0;
+
+        while (snippets.Count < 5
+            && (idx = html.IndexOf(marker, idx, StringComparison.Ordinal)) >= 0)
+        {
+            var tagEnd = html.IndexOf('>', idx);
+            if (tagEnd < 0) break;
+
+            var start = tagEnd + 1;
+            var end = html.IndexOf("</", start, StringComparison.Ordinal);
+            if (end <= start) { idx = start; continue; }
+
+            // Strip inner HTML tags
+            var raw = html[start..end];
+            var text = StripTags(raw);
+            text = WebUtility.HtmlDecode(text).Trim();
+
+            if (!string.IsNullOrWhiteSpace(text))
+                snippets.Add(text);
+
+            idx = end;
+        }
+
+        return snippets;
+    }
+
+    private static string StripTags(string input)
+    {
+        var output = new System.Text.StringBuilder(input.Length);
+        var inTag = false;
+
+        foreach (var ch in input)
+        {
+            if (ch == '<') { inTag = true; continue; }
+            if (ch == '>') { inTag = false; continue; }
+            if (!inTag) output.Append(ch);
+        }
+
+        return output.ToString();
+    }
+}

